import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void threeConsecutiveFailsLocks() {
        assertEquals("LOCKED",
                new Solution().finalState(
                        new String[]{"INSERT_CARD", "PIN_FAIL", "PIN_FAIL", "PIN_FAIL"}));
    }

    @Test
    void ejectResetsCounterThenTwoMoreFails() {
        // EJECT after 1 fail → pinFails resets; then 2 more fails → AWAITING_PIN (not locked)
        assertEquals("AWAITING_PIN",
                new Solution().finalState(
                        new String[]{"INSERT_CARD", "PIN_FAIL", "EJECT",
                                     "INSERT_CARD", "PIN_FAIL", "PIN_FAIL"}));
    }

    @Test
    void successfulSession() {
        assertEquals("IDLE",
                new Solution().finalState(
                        new String[]{"INSERT_CARD", "PIN_OK", "WITHDRAW", "DEPOSIT", "EJECT"}));
    }

    @Test
    void emptyEvents() {
        assertEquals("IDLE",
                new Solution().finalState(new String[]{}));
    }

    @Test
    void lockedIsTerminal() {
        // After LOCKED, all further events are no-ops
        assertEquals("LOCKED",
                new Solution().finalState(
                        new String[]{"INSERT_CARD", "PIN_FAIL", "PIN_FAIL", "PIN_FAIL",
                                     "PIN_OK", "WITHDRAW", "EJECT"}));
    }

    @Test
    void pinOkResetsThenEjectReturnsIdle() {
        // PIN_OK resets pinFails; after authenticated session, EJECT → IDLE
        assertEquals("IDLE",
                new Solution().finalState(
                        new String[]{"INSERT_CARD", "PIN_FAIL", "PIN_FAIL",
                                     "PIN_OK", "EJECT"}));
    }

    @Test
    void idleIgnoresOtherEvents() {
        // Events other than INSERT_CARD from IDLE are no-ops
        assertEquals("IDLE",
                new Solution().finalState(
                        new String[]{"WITHDRAW", "DEPOSIT", "PIN_OK", "EJECT"}));
    }
}
